#!/usr/bin/env python3
"""Generate a CMakeLists.txt for one single-bitstream RO job."""

import argparse
import os
import sys

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
from dataset_config import ITERATION_LABEL, SHELL_PARAMS


TEMPLATE = """\
######################################################################################
# {label} - {{job_id}}
# Source batch: {{batch_id}} | Floorplan: {{fp_id}} | Original config: {{config_local}}
#
# Auto-generated by gen_single_job_cmake.py - do not edit manually
######################################################################################

cmake_minimum_required(VERSION 3.5)
set(CYT_DIR ${{{{CMAKE_SOURCE_DIR}}}}/../../../../../../)
set(CMAKE_MODULE_PATH ${{{{CMAKE_MODULE_PATH}}}} ${{{{CYT_DIR}}}}/cmake)
find_package(CoyoteHW REQUIRED)

project({{job_id}})
message("*** {label}: {{job_id}} ***")

set(FDEV_NAME   "{{fdev_name}}")
set(N_REGIONS   {{n_regions}})
set(EN_PR       {{en_pr}})
set(N_CONFIG    1)
set(EN_STRM     {{en_strm}})
set(N_STRM_AXI  {{n_strm_axi}})
set(EN_MEM      {{en_mem}})

set(FPLAN_PATH "${{{{CMAKE_SOURCE_DIR}}}}/floorplans/{{fplan_file}}")

validation_checks_hw()

load_apps(
    VFPGA_C0_0   "apps/standalone/ro_{{ro_count:04d}}"   # original {{batch_id}} config {{config_local}}, N_RO={{ro_count}}
)

create_hw()
""".format(label=ITERATION_LABEL)


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--job-id", required=True)
    parser.add_argument("--batch-id", required=True)
    parser.add_argument("--fp-id", required=True)
    parser.add_argument("--fplan-file", required=True)
    parser.add_argument("--config-local", required=True, type=int)
    parser.add_argument("--ro-count", required=True, type=int)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    content = TEMPLATE.format(
        job_id=args.job_id,
        batch_id=args.batch_id,
        fp_id=args.fp_id,
        fplan_file=args.fplan_file,
        config_local=args.config_local,
        ro_count=args.ro_count,
        fdev_name=SHELL_PARAMS["FDEV_NAME"],
        n_regions=SHELL_PARAMS["N_REGIONS"],
        en_pr=SHELL_PARAMS["EN_PR"],
        en_strm=SHELL_PARAMS["EN_STRM"],
        n_strm_axi=SHELL_PARAMS["N_STRM_AXI"],
        en_mem=SHELL_PARAMS["EN_MEM"],
    )

    os.makedirs(os.path.dirname(args.output), exist_ok=True)
    with open(args.output, "w") as f:
        f.write(content)
    print(f"Generated {args.output}")


if __name__ == "__main__":
    main()
